import re
from collections import Counter

STEREOTYPE_PATTERNS = {
    'gender': [
        r'\bnurse\b.*\b(she|her|woman|female)',
        r'\bengineer\b.*\b(he|him|man|male)'
    ],
    'race': [
        r'\bghetto\b.*\b(black|african-american)',
        r'\bmodel\b.*\b(asian|chinese)'
    ]
}

def scan_stereotypes(text: str) -> Dict[str, int]:
    findings = Counter()
    for category, patterns in STEREOTYPE_PATTERNS.items():
        for pattern in patterns:
            matches = len(re.findall(pattern, text, re.IGNORECASE))
            findings[f'{category}_{pattern}'] = matches

    high_risk = sum(count for count in findings.values() if count > 0)
    return {'stereotype_hits': high_risk, 'details': dict(findings)}

# Integrate with OpenAI Agents tracing
trace.on_output(lambda output: scan_stereotypes(output['content']))

