class BiasAccumulator:
    def __init__(self):
        self.bias_chain: List[float] = []

    def record_bias(self, bias_score: float):
        self.bias_chain.append(bias_score)
        return {
            'current_bias': bias_score,
            'chain_bias': sum(self.bias_chain) / len(self.bias_chain),
            'escalation': bias_score > 0.2
        }

