from openai_agents import Agent

BIAS_REWRITERS = {
    'gender': lambda text: re.sub(
        r'\bnurse\b.*\b(she|her)',
        'healthcare professional',
        text,
        flags=re.IGNORECASE
    ),
    'race': lambda text: re.sub(
        r'\bghetto\b.*\b(black)',
        'underserved community',
        text,
        flags=re.IGNORECASE
    )
}

def rewrite_fair_output(biased_text: str, bias_type: str) -> str:
    """Rewrite biased text while preserving semantic intent"""
    rewriter = BIAS_REWRITERS.get(bias_type)
    if rewriter:
        return rewriter(biased_text)
    return biased_text

class FairnessAgent(Agent):
    def process_output(self, output):
        bias_report = self.guardrails['bias_detector'](output)
        if bias_report['flagged']:
            fair_output = rewrite_fair_output(
                output['content'],
                bias_report['primary_bias']
            )
            output['content'] = fair_output
            output['bias_fixed'] = True
        return output

hiring_agent = FairnessAgent(name="fair-hiring")

from openai_agents import Agent, Tool
from typing import List

import numpy as np

class BalancedSampler:
    def __init__(self):
        self.group_quotas = {'female': 0.5, 'male': 0.5, 'minority': 0.3}

    def enforce_balance(self, candidates: List[Dict]) -> List[Dict]:
        """Enforce demographic quotas in candidate sampling"""
        grouped = self._group_candidates(candidates)

        balanced = []
        for group, quota in self.group_quotas.items():
            group_size = int(len(candidates) * quota)
            if group in grouped and len(grouped[group]) > 0:
                balanced.extend(np.random.choice(
                    grouped[group], 
                    min(group_size, len(grouped[group])),
                    replace=False
                ))

        return balanced[:len(candidates)]

sampler_tool = Tool(
    name="balanced_sampler",
    func=lambda candidates: BalancedSampler().enforce_balance(candidates)
)

eval_agent = Agent(tools=[sampler_tool])

